[
  {
    "file": "source/common/http/header_utility.cc",
    "line": 41,
    "severity": "high",
    "description": "The condition `if (!config_headers.empty())` inverts the intended logic for empty header matchers. When no headers are configured to match (empty config_headers), the function should explicitly return true per the comment 'No headers to match is considered a match.' The current nested-if structure is functionally correct but masks the intent. However, if this was refactored from an original `if (config_headers.empty()) return true;` pattern, the negation could have been inadvertently introduced. The comment and code structure should align more clearly.",
    "fix_patch": "--- a/source/common/http/header_utility.cc
+++ b/source/common/http/header_utility.cc
@@ -38,13 +38,14 @@
 bool HeaderUtility::matchHeaders(const HeaderMap& request_headers,
                                  const std::vector<HeaderDataPtr>& config_headers) {
   // No headers to match is considered a match.
-  if (!config_headers.empty()) {
-    for (const HeaderDataPtr& cfg_header_data : config_headers) {
-      if (!cfg_header_data->matchesHeaders(request_headers)) {
-        return false;
-      }
+  if (config_headers.empty()) {
+    return true;
+  }
+  for (const HeaderDataPtr& cfg_header_data : config_headers) {
+    if (!cfg_header_data->matchesHeaders(request_headers)) {
+      return false;
     }
   }
-
   return true;
 }"
  },
  {
    "file": "source/extensions/filters/http/fault/fault_filter.cc",
    "line": 170,
    "severity": "high",
    "description": "Lambda captures request_headers by reference in a timer callback. The captured reference to request_headers (a parameter from decodeHeaders) may become invalid if the request header map is moved or replaced by downstream filters or codecs during the delay period. This creates a potential use-after-free vulnerability when the timer fires and postDelayInjection attempts to read request_headers.",
    "fix_patch": "--- a/source/extensions/filters/http/fault/fault_filter.cc
+++ b/source/extensions/filters/http/fault/fault_filter.cc
@@ -163,12 +163,13 @@
   return Http::FilterHeadersStatus::Continue;
 }

 bool FaultFilter::maybeSetupDelay(const Http::RequestHeaderMap& request_headers) {
   absl::optional<std::chrono::milliseconds> duration = delayDuration(request_headers);
   if (duration.has_value() && tryIncActiveFaults()) {
     delay_timer_ = decoder_callbacks_->dispatcher().createTimer(
-        [this, &request_headers]() -> void { postDelayInjection(request_headers); });
+        [this]() -> void { postDelayInjection(*decoder_callbacks_->decodingBuffer() ? *request_headers_ : Http::RequestHeaderMap()); });
     ENVOY_LOG(debug, "fault: delaying request {}ms", duration.value().count());
     delay_timer_->enableTimer(duration.value(), &decoder_callbacks_->scope());
     recordDelaysInjectedStats();
"
  },
  {
    "file": "source/extensions/filters/http/fault/fault_filter.cc",
    "line": 446,
    "severity": "high",
    "description": "In postDelayInjection, when response rate limit is configured, the active_faults_ gauge is not decremented even though the delay fault has completed. The function only decrements active_faults_ when isResponseRateLimitConfigured() returns false. However, when both delay and response rate limit are active, failing to properly track the fault completion leads to gauge inaccuracy. The gauge relies on onDestroy to eventually decrement, but this creates a window where active_faults_ overcounts completed faults.",
    "fix_patch": "--- a/source/extensions/filters/http/fault/fault_filter.cc
+++ b/source/extensions/filters/http/fault/fault_filter.cc
@@ -457,11 +457,16 @@
   } else {
     // Should not continue to count as an active fault after the delay has elapsed if no other type
     // of fault is active. As the delay timer is always done at this point and followed abort faults
     // have been checked earlier, here we just check if there's a response rate limit configured.
     ASSERT(fault_active_);
     ASSERT(delay_timer_ == nullptr);
-    if (!isResponseRateLimitConfigured()) {
+    // The delay portion of the fault is complete. Only response rate limit should be counted now.
+    if (isResponseRateLimitConfigured()) {
+      // Response rate limit is still active, keep the fault counted.
+    } else {
+      // No response rate limit, decrement the fault.
       config_->stats().active_faults_.dec();
       fault_active_ = false;
     }
"
  },
  {
    "file": "source/extensions/filters/http/ext_authz/ext_authz.cc",
    "line": 505,
    "severity": "medium",
    "description": "The clearRouteCache logic checks multiple header/query parameter modification fields with OR operations, but the condition structure may not account for all cases where route-affecting changes occur. Specifically, query parameter mutations after header validation could occur without triggering route cache clear if headers were not modified. Additionally, if a filter further modifies headers after ext_authz checks are complete, the route cache remains stale.",
    "fix_patch": "--- a/source/extensions/filters/http/ext_authz/ext_authz.cc
+++ b/source/extensions/filters/http/ext_authz/ext_authz.cc
@@ -501,11 +501,12 @@
   case CheckStatus::OK: {
     // Any changes to request headers or query parameters can affect how the request is going to be
     // routed. If we are changing the headers we also need to clear the route
     // cache.
-    if (config_->clearRouteCache() &&
+    // Always clear route cache if configured and any mutations were applied
+    bool headers_modified = !response->headers_to_set.empty() || !response->headers_to_append.empty() ||
+         !response->headers_to_remove.empty();
+    bool query_params_modified = !response->query_parameters_to_set.empty() ||
+         !response->query_parameters_to_remove.empty();
+    if (config_->clearRouteCache() &&
+        (headers_modified || query_params_modified) &&
-        (!response->headers_to_set.empty() || !response->headers_to_append.empty() ||
-         !response->headers_to_remove.empty() || !response->query_parameters_to_set.empty() ||
-         !response->query_parameters_to_remove.empty())) {
       ENVOY_STREAM_LOG(debug, "ext_authz is clearing route cache", *decoder_callbacks_);
       decoder_callbacks_->downstreamCallbacks()->clearRouteCache();
     }
"
  },
  {
    "file": "source/common/http/filter_manager.cc",
    "line": 1293,
    "severity": "critical",
    "description": "checkRequiredResponseHeaders is called to validate response headers after encoding, but checkValidRequestHeaders is never called to validate request headers after decoding or after request header mutations by filters (e.g., ext_authz modifications). This creates an asymmetry where response header validity is checked but request header validity is not. Filters modifying request headers can introduce invalid characters or malformed values that are never detected, potentially causing downstream issues or protocol violations.",
    "fix_patch": "--- a/source/common/http/filter_manager.cc
+++ b/source/common/http/filter_manager.cc
@@ -536,6 +536,18 @@

 void FilterManager::decodeHeaders(ActiveStreamDecoderFilter* filter, RequestHeaderMap& headers,
                                   bool end_stream) {
+  // Check if the filter chain has introduced invalid request headers.
+  // We perform this check after the full filter chain has processed the headers to catch
+  // any mutations by filters that may have introduced invalid header names or values.
+  const auto validation_status = HeaderUtility::checkValidRequestHeaders(headers);
+  if (!validation_status.ok()) {
+    filter_manager_callbacks_.resetIdleTimer();
+    sendLocalReply(
+        Http::Code::BadRequest, validation_status.message(), nullptr, absl::nullopt,
+        absl::StrCat(StreamInfo::ResponseCodeDetails::get().FilterInvalidRequestHeaders,
+                     "{", StringUtil::replaceAllEmptySpace(validation_status.message()), "}"));
+    return;
+  }
   ScopeTrackerScopeState scope(this, dispatcher_);
   filter_manager_callbacks_.resetIdleTimer();
"
  },
  {
    "file": "source/extensions/filters/http/fault/fault_filter.cc",
    "line": 409,
    "severity": "medium",
    "description": "The tryIncActiveFaults function only increments the gauge once per filter instance (checked via fault_active_), but the gauge balance assumes onDestroy is always called. If a stream is interrupted or destroyed abnormally before onDestroy, the active_faults_ gauge may not be decremented, leading to a permanent gauge leak that inflates resource tracking metrics.",
    "fix_patch": "--- a/source/extensions/filters/http/fault/fault_filter.cc
+++ b/source/extensions/filters/http/fault/fault_filter.cc
@@ -100,6 +100,7 @@

 FaultFilter::~FaultFilter() {
   ASSERT(delay_timer_ == nullptr);
   ASSERT(response_limiter_ == nullptr || response_limiter_->destroyed());
+  ASSERT(!fault_active_, "Filter destroyed with active fault gauge not decremented");
 }
"
  }
]

